const UNITS = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 };

function parseDuration(str) {
  if (typeof str !== 'string' || str === '') {
    throw new Error(`parseDuration: invalid input: ${str}`);
  }

  // Bare integer → milliseconds
  if (/^\d+$/.test(str)) return parseInt(str, 10);

  // One or more <integer><unit> segments; ms alternation before m ensures correct tokenization
  const segRe = /(\d+)(ms|s|m|h|d)/g;
  let total = 0;
  let consumed = 0;
  let match;
  while ((match = segRe.exec(str)) !== null) {
    if (match.index !== consumed) {
      throw new Error(`parseDuration: unparseable input: ${str}`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    consumed = segRe.lastIndex;
  }

  if (consumed !== str.length) {
    throw new Error(`parseDuration: unparseable input: ${str}`);
  }

  return total;
}

